		let localX = i % aabbW;
		let localY = i / aabbW;
		let tx = minTileX + i32(localX);
		let ty = minTileY + i32(localY);
		let tMin = vec2f(f32(tx) * f32(TILE_SIZE), f32(ty) * f32(TILE_SIZE));
		let tMax = tMin + vec2f(f32(TILE_SIZE));
